import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import './Upload.css';

const Upload = () => {
  const navigate = useNavigate();
  
  // Check authentication from localStorage
  const [user, setUser] = useState(null);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  
  const [file, setFile] = useState(null);
  const [uploading, setUploading] = useState(false);
  const [loading, setLoading] = useState(false);
  
  // Form data with all details
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    course: 'B.Tech',
    branch: 'CSE',
    year: '1',
    semester: '1',
    subject: '',
    subjectCode: '',
    type: 'notes',
    tags: ''
  });

  // Available options
  const courses = ['B.Tech', 'BCA', 'BBA', 'MBA', 'MCA'];
  const branches = ['CSE', 'ECE', 'EEE', 'ME', 'CE', 'IT', 'Other'];
  const years = ['1', '2', '3', '4'];
  const semesters = ['1', '2', '3', '4', '5', '6', '7', '8'];
  const materialTypes = [
    { value: 'notes', label: '📄 Notes' },
    { value: 'pyq', label: '📝 Previous Year Questions (PYQ)' },
    { value: 'syllabus', label: '📋 Syllabus' },
    { value: 'lab', label: '🔬 Lab Manuals' },
    { value: 'assignment', label: '📝 Assignments' },
    { value: 'presentation', label: '📊 Presentations' },
    { value: 'important', label: '❓ Important Questions' },
    { value: 'book', label: '📚 Reference Books' }
  ];

  // Common subjects based on course and branch
  const getSubjects = () => {
    const { course, branch, year, semester } = formData;
    
    if (course === 'B.Tech' && branch === 'CSE') {
      if (year === '1' && semester === '1') {
        return [
          'Mathematics-I',
          'Physics',
          'Chemistry',
          'Programming in C',
          'English Communication',
          'Engineering Graphics'
        ];
      } else if (year === '1' && semester === '2') {
        return [
          'Mathematics-II',
          'Digital Electronics',
          'Data Structures',
          'Discrete Mathematics',
          'Environmental Science'
        ];
      } else if (year === '2' && semester === '3') {
        return [
          'Object Oriented Programming',
          'Computer Organization',
          'Database Management Systems',
          'Theory of Computation',
          'Probability & Statistics'
        ];
      } else if (year === '2' && semester === '4') {
        return [
          'Operating Systems',
          'Computer Networks',
          'Design & Analysis of Algorithms',
          'Microprocessors',
          'Formal Language & Automata'
        ];
      }
    }
    
    if (course === 'BCA') {
      if (year === '1' && semester === '1') {
        return [
          'Programming Fundamentals',
          'Digital Logic',
          'Business Communication',
          'Mathematics-I',
          'Computer Fundamentals'
        ];
      }
    }
    
    if (course === 'BBA') {
      if (year === '1' && semester === '1') {
        return [
          'Principles of Management',
          'Business Economics',
          'Financial Accounting',
          'Business Mathematics',
          'Business Communication'
        ];
      }
    }
    
    // Default subjects
    return [
      'Mathematics',
      'Physics',
      'Chemistry',
      'Computer Science',
      'Electronics',
      'Mechanical',
      'Civil',
      'Electrical',
      'Other'
    ];
  };

  useEffect(() => {
    // DIRECT CHECK - Skip AuthContext
    const savedUser = localStorage.getItem('study_portal_user');
    const savedToken = localStorage.getItem('study_portal_token');
    
    if (savedUser && savedToken) {
      try {
        const userData = JSON.parse(savedUser);
        setUser(userData);
        setIsAuthenticated(true);
        
        // Auto-fill user's details
        if (userData.branch && !formData.branch) {
          setFormData(prev => ({ ...prev, branch: userData.branch }));
        }
        if (userData.semester && !formData.semester) {
          setFormData(prev => ({ ...prev, semester: userData.semester.toString() }));
        }
        if (userData.course && !formData.course) {
          setFormData(prev => ({ ...prev, course: userData.course }));
        }
        
      } catch (error) {
        console.error('Error parsing user:', error);
        navigate('/login');
      }
    } else {
      navigate('/login');
    }
  }, [navigate]);

  const handleFileChange = (e) => {
    const selectedFile = e.target.files[0];
    if (selectedFile) {
      if (selectedFile.size > 10 * 1024 * 1024) {
        alert('❌ File size exceeds 10MB limit');
        e.target.value = '';
        return;
      }
      setFile(selectedFile);
    }
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData({
      ...formData,
      [name]: value
    });
  };

  const generateSubjectCode = () => {
    const { course, branch, year, semester, subject } = formData;
    
    if (!subject) return '';
    
    // Generate code like: BTECH-CSE-201
    const courseCode = course.substring(0, 4).toUpperCase();
    const branchCode = branch.toUpperCase();
    const subjectNum = Math.floor(Math.random() * 900) + 100; // Random 3-digit
    
    return `${courseCode}-${branchCode}-${subjectNum}`;
  };

  const handleUpload = async () => {
    if (!file) {
      alert('❌ Please select a file');
      return;
    }
    if (!formData.title.trim()) {
      alert('❌ Please enter title');
      return;
    }
    if (!formData.subject) {
      alert('❌ Please select subject');
      return;
    }
    if (!formData.course) {
      alert('❌ Please select course');
      return;
    }

    // Generate subject code if not provided
    const subjectCode = formData.subjectCode || generateSubjectCode();

    const data = new FormData();
    data.append('file', file);
    data.append('title', formData.title);
    data.append('description', formData.description);
    data.append('course', formData.course);
    data.append('branch', formData.branch);
    data.append('year', formData.year);
    data.append('semester', formData.semester);
    data.append('subject', formData.subject);
    data.append('subjectCode', subjectCode);
    data.append('type', formData.type);
    data.append('tags', formData.tags);
    
    // Add user info
    if (user) {
      data.append('uploadedBy', user.id || user.email);
      data.append('uploaderName', user.name);
    }

    setUploading(true);

    try {
      const token = localStorage.getItem('study_portal_token');
      
      const response = await fetch('http://localhost:5000/api/materials/upload', {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`,
        },
        body: data,
      });

      const result = await response.json();
      
      if (response.ok) {
        if (result.status === 'pending' || result.message?.includes('approval')) {
          alert(`✅ ${result.message}\n\n📝 Status: Under Review\n👑 Admin approval required\n⏳ Will be visible after approval`);
        } else {
          alert(`✅ ${result.message || 'Upload successful!'}`);
        }
        
        // Reset form
        setFile(null);
        setFormData({
          title: '',
          description: '',
          course: 'B.Tech',
          branch: 'CSE',
          year: '1',
          semester: '1',
          subject: '',
          subjectCode: '',
          type: 'notes',
          tags: ''
        });
        document.getElementById('fileInput').value = '';
        
      } else {
        alert(`❌ Upload failed: ${result.error || 'Server error'}`);
      }
      
    } catch (error) {
      alert(`❌ Upload failed: ${error.message || 'Network error'}`);
      console.error('Upload error:', error);
    } finally {
      setUploading(false);
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('study_portal_token');
    localStorage.removeItem('study_portal_user');
    window.location.href = '/';
  };

  // Show loading while checking authentication
  if (!user && isAuthenticated === false) {
    return (
      <div style={{
        display: 'flex',
        justifyContent: 'center',
        alignItems: 'center',
        height: '100vh',
        background: 'linear-gradient(135deg, #f8fafc 0%, #e2e8f0 100%)'
      }}>
        <div>Loading authentication...</div>
      </div>
    );
  }

  const subjects = getSubjects();

  return (
    <div className="upload-container">
      {/* Header with logout button */}
      <div className="upload-header-row">
        <header className="upload-header">
          <h1 className="upload-title">Upload Study Materials</h1>
          <p className="upload-subtitle">
            Share your notes, PYQs, and study materials with complete details
          </p>
        </header>
        
        <button onClick={handleLogout} className="logout-button">
          Logout
        </button>
      </div>

      {/* User Info */}
      <div className="user-info">
        <div className="user-avatar">
          {user?.name?.charAt(0)?.toUpperCase() || 'U'}
        </div>
        <div className="user-details">
          <p className="user-name">
            Uploading as: <span>{user?.name || 'User'}</span>
          </p>
          <p className="user-meta">
            {user?.branch || 'Branch'} • Semester {user?.semester || 'Semester'} • {user?.email || 'Email'}
          </p>
        </div>
      </div>

      {/* Info Box */}
      <div className="info-box">
        <p><strong>📋 Instructions:</strong> Fill all details accurately. This helps other students find your materials easily.</p>
      </div>

      {/* File Upload Section */}
      <div className="upload-box">
        <input
          type="file"
          id="fileInput"
          className="file-input"
          onChange={handleFileChange}
          accept=".pdf,.doc,.docx,.ppt,.pptx,.txt,.jpg,.jpeg,.png"
        />
        <label htmlFor="fileInput" className="upload-label">
          📁 Choose File to Upload
        </label>
        
        {file && (
          <div className="file-info">
            <p><strong>Selected:</strong> {file.name}</p>
            <p><strong>Size:</strong> {(file.size / 1024).toFixed(2)} KB</p>
            <p><strong>Type:</strong> {file.type}</p>
          </div>
        )}
        
        <p className="file-types">
          📎 Supported: PDF, DOC, DOCX, PPT, PPTX, TXT, JPG, JPEG, PNG
          <br />
          ⚠️ Maximum file size: 10MB
        </p>
      </div>

      {/* Upload Form */}
      <div className="upload-form">
        <h3 className="form-section-title">📄 Material Details</h3>
        
        {/* Title */}
        <div className="form-group">
          <label className="form-label">
            Title * <small>(Descriptive title of your material)</small>
          </label>
          <input
            type="text"
            name="title"
            placeholder="e.g., Complete Data Structures Notes, Operating Systems PYQ 2023"
            value={formData.title}
            onChange={handleInputChange}
            className="form-input"
            required
          />
        </div>

        {/* Description */}
        <div className="form-group">
          <label className="form-label">
            Description <small>(Optional details about the material)</small>
          </label>
          <textarea
            name="description"
            placeholder="Describe what's included in this material, important topics covered, etc."
            value={formData.description}
            onChange={handleInputChange}
            className="form-textarea"
            rows="3"
          />
        </div>

        <h3 className="form-section-title">🎓 Academic Details</h3>
        
        <div className="form-row">
          {/* Course */}
          <div className="form-group half">
            <label className="form-label">Course *</label>
            <select
              name="course"
              value={formData.course}
              onChange={handleInputChange}
              className="form-select"
              required
            >
              <option value="">Select Course</option>
              {courses.map(course => (
                <option key={course} value={course}>{course}</option>
              ))}
            </select>
          </div>

          {/* Branch */}
          <div className="form-group half">
            <label className="form-label">Branch *</label>
            <select
              name="branch"
              value={formData.branch}
              onChange={handleInputChange}
              className="form-select"
              required
            >
              <option value="">Select Branch</option>
              {branches.map(branch => (
                <option key={branch} value={branch}>{branch}</option>
              ))}
            </select>
          </div>
        </div>

        <div className="form-row">
          {/* Year */}
          <div className="form-group half">
            <label className="form-label">Year *</label>
            <select
              name="year"
              value={formData.year}
              onChange={handleInputChange}
              className="form-select"
              required
            >
              <option value="">Select Year</option>
              {years.map(year => (
                <option key={year} value={year}>Year {year}</option>
              ))}
            </select>
          </div>

          {/* Semester */}
          <div className="form-group half">
            <label className="form-label">Semester *</label>
            <select
              name="semester"
              value={formData.semester}
              onChange={handleInputChange}
              className="form-select"
              required
            >
              <option value="">Select Semester</option>
              {semesters.map(sem => (
                <option key={sem} value={sem}>Semester {sem}</option>
              ))}
            </select>
          </div>
        </div>

        {/* Subject */}
        <div className="form-group">
          <label className="form-label">Subject *</label>
          <select
            name="subject"
            value={formData.subject}
            onChange={handleInputChange}
            className="form-select"
            required
          >
            <option value="">Select Subject</option>
            {subjects.map(subject => (
              <option key={subject} value={subject}>{subject}</option>
            ))}
          </select>
        </div>

        <div className="form-row">
          {/* Subject Code */}
          <div className="form-group half">
            <label className="form-label">
              Subject Code <small>(Auto-generated)</small>
            </label>
            <input
              type="text"
              name="subjectCode"
              placeholder="e.g., CSE-301"
              value={formData.subjectCode || generateSubjectCode()}
              onChange={handleInputChange}
              className="form-input"
              readOnly
              style={{ background: '#f3f4f6' }}
            />
          </div>

          {/* Material Type */}
          <div className="form-group half">
            <label className="form-label">Material Type *</label>
            <select
              name="type"
              value={formData.type}
              onChange={handleInputChange}
              className="form-select"
              required
            >
              {materialTypes.map(type => (
                <option key={type.value} value={type.value}>{type.label}</option>
              ))}
            </select>
          </div>
        </div>

        {/* Tags */}
        <div className="form-group">
          <label className="form-label">
            Tags <small>(Comma separated, e.g., important, unit1, theory)</small>
          </label>
          <input
            type="text"
            name="tags"
            placeholder="important, unit1, theory, practical"
            value={formData.tags}
            onChange={handleInputChange}
            className="form-input"
          />
        </div>

        {/* Upload Button */}
        <button
          onClick={handleUpload}
          disabled={uploading || !file || !formData.title || !formData.subject}
          className="upload-btn"
        >
          {uploading ? '⏳ Uploading...' : '📤 Upload Material'}
        </button>

        <div className="admin-note">
          <p className="admin-note-content">
            <span>⚠️</span>
            <span>
              <strong>Note:</strong> All uploads require admin approval. 
              Your file will be visible after review. Please provide accurate details.
            </span>
          </p>
        </div>
      </div>
    </div>
  );
};

export default Upload;
